app.use(helmet()); // sets 11 security-relevant headers at once
```

---

### 4. No Rate Limiting (OWASP A04 — Insecure Design)

All endpoints are open to brute-force and denial-of-service. There is no throttling on any route.

**Fix:**

```bash
npm install express-rate-limit
```

```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});

